#include<bits/stdc++.h>
using namespace std;
int s[500005];
vector<int> e[500005];
vector<int> a[500005][2];
int ans[500005];
bool v[500005];
int sfind(int x) {
	if (s[x] == x) {
		return x;
	} else {
		return s[x] = sfind(s[x]);
	}
}
void smerge(int x, int y) {
	int fx = sfind(x);
	int fy = sfind(y);
	if (fx == fy) {
		return;
	}
	s[fy] = fx;
	return;

}
void lca(int x, int fa) {
	v[x] = 1;
	for (int i = 0; i < a[x][0].size(); i++) {
		if (v[a[x][0][i]]) {
			ans[a[x][1][i]] = sfind(a[x][0][i]);
		}
	}
	for (int i = 0; i < e[x].size(); i++) {
		if (e[x][i] != fa) {
			lca(e[x][i], x);
			smerge(x, e[x][i]);
		}
	}
	return;
}
int main() {
	int n, m, root;
	cin >> n >> m >> root;
	for (int i = 1; i < n; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
    for (int i = 1; i <= n; i++) {
		s[i] = i;
	}
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		a[x][0].push_back(y);
		a[x][1].push_back(i);
		a[y][0].push_back(x);
		a[y][1].push_back(i);
	}
	lca(root,-1);
	for (int i = 1; i <= m; i++) {
		cout << ans[i] << "\n";
	}
	return 0;
}
